import modal

app = modal.App("class-inference-warm")

image = modal.Image.debian_slim().pip_install("numpy")

@app.cls(image=image, min_containers=1)
class TextClassifier:
    @modal.enter()
    def setup(self):
        self.model = "my-awesome-model"
        self.call_count = 0

    @modal.method()
    def classify(self, text: str):
        self.call_count += 1
        label = "neutral"
        text_lower = text.lower()
        if "good" in text_lower or "great" in text_lower or "positive" in text_lower:
            label = "positive"
        elif "bad" in text_lower or "terrible" in text_lower or "negative" in text_lower:
            label = "negative"

        return {
            "label": label,
            "confidence": 0.95,
            "call_count": self.call_count
        }

    @modal.method()
    def get_stats(self):
        return {
            "model_info": self.model,
            "total_calls": self.call_count
        }

@app.local_entrypoint()
def main():
    classifier = TextClassifier()

    # Make exactly 3 calls
    res1 = classifier.classify.remote("This is a great day!")
    res2 = classifier.classify.remote("I feel terrible about this.")
    res3 = classifier.classify.remote("The weather is okay.")

    print("Result 1:", res1)
    print("Result 2:", res2)
    print("Result 3:", res3)

    # Get stats
    stats = classifier.get_stats.remote()
    print("Stats:", stats)

    # Store results in Modal Dict
    d = modal.Dict.from_name("class-inference-output", create_if_missing=True)
    d["stats"] = stats
    d["classifications"] = 3
    print("Stored results in Modal Dict.")

